namespace sv_da423523ac9f486387eaf2c9987b0876.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@* Vertical navigation tabs for settings sections *@

<nav class="settings-sidebar">
    <ul class="nav nav-pills flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item" @key="section.Key">
                <button class="nav-link w-100 text-start @(section.Key == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@using sv_da423523ac9f486387eaf2c9987b0876.Services

<div class="settings-section">
    <h3 class="mb-4">Profile Settings</h3>

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="displayName" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="bio" @bind:event="oninput"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="text-center">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-preview mb-2">
                    @if (!string.IsNullOrWhiteSpace(avatarUrl))
                    {
                        <img src="@avatarUrl" alt="Avatar" class="rounded-circle img-fluid" style="width:120px;height:120px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center" style="width:120px;height:120px;margin:0 auto;">
                            <span class="text-white fs-1">👤</span>
                        </div>
                    }
                </div>
                <small class="text-muted text-break">@avatarUrl</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @if (saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
            Discard Changes
        </button>
    </div>

    @if (showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnProfileSaved { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool saving;
    private bool showSuccess;
    private CancellationTokenSource? toastCts;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !saving)
        {
            CopyFromProfile();
        }
    }

    private void CopyFromProfile()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnProfileSaved.InvokeAsync(updated);
            showSuccess = true;
            StateHasChanged();
            await ShowToastAsync();
        }
        finally
        {
            saving = false;
        }
    }

    private async Task ShowToastAsync()
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        try
        {
            await Task.Delay(3000, toastCts.Token);
            showSuccess = false;
        }
        catch (TaskCanceledException) { }
    }

    private void Discard()
    {
        CopyFromProfile();
        showSuccess = false;
    }
}

@using sv_da423523ac9f486387eaf2c9987b0876.Services

<div class="settings-section">
    <h3 class="mb-4">Notification Preferences</h3>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    @if (channels.Count == 0)
    {
        <p class="text-muted">No channels available.</p>
    }
    else
    {
        <div class="list-group mb-4">
            @foreach (var channel in channels)
            {
                <label class="list-group-item d-flex align-items-center" @key="channel.Name">
                    <input class="form-check-input me-2" type="checkbox"
                           checked="@channel.Muted"
                           @onchange="() => ToggleMute(channel)" />
                    <span>@channel.Name</span>
                    @if (channel.Muted)
                    {
                        <span class="badge bg-warning ms-auto">Muted</span>
                    }
                </label>
            }
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @if (saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (showSuccess)
    {
        <div class="alert alert-success mt-3">✅ Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnPrefsSaved { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private List<ChannelState> channels = [];
    private bool saving;
    private bool showSuccess;
    private CancellationTokenSource? toastCts;

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            channels = Prefs.MutedChannels
                .Select(c => new ChannelState { Name = c, Muted = true })
                .ToList();

            // Ensure we always show some channels for demo purposes
            if (channels.Count == 0)
            {
                channels =
                [
                    new() { Name = "general", Muted = false },
                    new() { Name = "announcements", Muted = false },
                    new() { Name = "random", Muted = false },
                    new() { Name = "engineering", Muted = false }
                ];
            }
        }
    }

    private void ToggleMute(ChannelState channel)
    {
        channel.Muted = !channel.Muted;
    }

    private async Task SaveAsync()
    {
        saving = true;
        try
        {
            var mutedList = channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedList);
            await OnPrefsSaved.InvokeAsync(updated);
            showSuccess = true;
            StateHasChanged();
            await ShowToastAsync();
        }
        finally
        {
            saving = false;
        }
    }

    private async Task ShowToastAsync()
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        try
        {
            await Task.Delay(3000, toastCts.Token);
            showSuccess = false;
        }
        catch (TaskCanceledException) { }
    }
}

@using sv_da423523ac9f486387eaf2c9987b0876.Services

<div class="settings-section">
    <h3 class="mb-4">Security Settings</h3>

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex align-items-center justify-content-between"
             role="button"
             @onclick="() => passwordPanelOpen = !passwordPanelOpen">
            <strong>Change Password</strong>
            <span>@(passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="confirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(passwordError))
                {
                    <div class="alert alert-danger">@passwordError</div>
                }
                @if (passwordSuccess)
                {
                    <div class="alert alert-success">✅ Password updated successfully!</div>
                }

                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@changingPassword">
                    @if (changingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex align-items-center justify-content-between">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="mt-1">
                    @if (Security.TwoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox"
                       checked="@Security.TwoFactorEnabled" disabled
                       id="twoFactorToggle" />
            </div>
        </div>
        @if (Security.LastPasswordChange.HasValue)
        {
            <div class="card-footer text-muted">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </div>
        }
    </div>

    @* Active Sessions *@
    <h5 class="mb-3">Active Sessions</h5>
    @if (Security.Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        <tr @key="session.Id">
                            <td>@session.Device</td>
