@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string currentPassword, string newPassword)> OnPasswordChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }

    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private bool passwordSuccess;
    private bool changingPassword;

    private ActiveSession? sessionToRevoke;
    private bool revoking;
    private string revokingSessionId = "";

    private async Task ChangePasswordAsync()
    {
        passwordError = null;
        passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            passwordError = "New password must be at least 8 characters.";
            return;
        }

        changingPassword = true;
        try
        {
            await OnPasswordChanged.InvokeAsync((currentPassword, newPassword));
            passwordSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (sessionToRevoke is null) return;

        revoking = true;
        revokingSessionId = sessionToRevoke.Id;
        try
        {
            await OnSessionRevoked.InvokeAsync(sessionToRevoke.Id);
            sessionToRevoke = null;
        }
        finally
        {
            revoking = false;
            revokingSessionId = "";
        }
    }
}

