        @if (Security.LastPasswordChange.HasValue)
        {
            <div class="card-footer text-muted">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </div>
        }
    </div>

    @* Active Sessions *@
    <h5 class="mb-3">Active Sessions</h5>
    @if (Security.Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        <tr @key="session.Id">
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
