</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnProfileSaved { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool saving;
    private bool showSuccess;
    private CancellationTokenSource? toastCts;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !saving)
        {
            CopyFromProfile();
        }
    }

    private void CopyFromProfile()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnProfileSaved.InvokeAsync(updated);
            showSuccess = true;
            StateHasChanged();
            await ShowToastAsync();
        }
        finally
        {
            saving = false;
        }
    }

    private async Task ShowToastAsync()
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        try
        {
            await Task.Delay(3000, toastCts.Token);
            showSuccess = false;
        }
        catch (TaskCanceledException) { }
    }

    private void Discard()
    {
        CopyFromProfile();
        showSuccess = false;
    }
}

