+
+    @* Change Password Panel *@
+    <div class="card mb-4">
+        <div class="card-header d-flex align-items-center justify-content-between"
+             role="button"
+             @onclick="() => passwordPanelOpen = !passwordPanelOpen">
+            <strong>Change Password</strong>
+            <span>@(passwordPanelOpen ? "▲" : "▼")</span>
+        </div>
+        @if (passwordPanelOpen)
+        {
+            <div class="card-body">
+                <div class="mb-3">
+                    <label class="form-label">Current Password</label>
+                    <input type="password" class="form-control" @bind="currentPassword" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">New Password</label>
+                    <input type="password" class="form-control" @bind="newPassword" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Confirm New Password</label>
+                    <input type="password" class="form-control" @bind="confirmPassword" />
+                </div>
+
+                @if (!string.IsNullOrEmpty(passwordError))
+                {
+                    <div class="alert alert-danger">@passwordError</div>
+                }
+                @if (passwordSuccess)
+                {
+                    <div class="alert alert-success">✅ Password updated successfully!</div>
+                }
+
+                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@changingPassword">
+                    @if (changingPassword)
+                    {
+                        <span class="spinner-border spinner-border-sm me-1"></span>
+                    }
+                    Update Password
+                </button>
+            </div>
+        }
+    </div>
+
+    @* Two-Factor Authentication *@
+    <div class="card mb-4">
+        <div class="card-body d-flex align-items-center justify-content-between">
+            <div>
+                <strong>Two-Factor Authentication</strong>
+                <div class="mt-1">
+                    @if (Security.TwoFactorEnabled)
+                    {
+                        <span class="badge bg-success">Enabled</span>
+                    }
+                    else
+                    {
+                        <span class="badge bg-secondary">Disabled</span>
+                    }
+                </div>
+            </div>
+            <div class="form-check form-switch">
+                <input class="form-check-input" type="checkbox"
+                       checked="@Security.TwoFactorEnabled" disabled
+                       id="twoFactorToggle" />
+            </div>
+        </div>
+        @if (Security.LastPasswordChange.HasValue)
+        {
+            <div class="card-footer text-muted">
+                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
+            </div>
+        }
+    </div>
+
+    @* Active Sessions *@
+    <h5 class="mb-3">Active Sessions</h5>
+    @if (Security.Sessions.Count == 0)
+    {
+        <p class="text-muted">No active sessions.</p>
+    }
+    else
+    {
+        <div class="table-responsive">
+            <table class="table table-hover">
+                <thead>
+                    <tr>
+                        <th>Device</th>
+                        <th>Location</th>
+                        <th>Last Active</th>
+                        <th></th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var session in Security.Sessions)
+                    {
+                        <tr @key="session.Id">
+                            <td>@session.Device</td>
+                            <td>@session.Location</td>
+                            <td>@session.LastActive.ToString("g")</td>
+                            <td>
+                                @if (session != Security.Sessions[0])
+                                {
+                                    <button class="btn btn-sm btn-outline-danger"
+                                            @onclick="() => PromptRevoke(session)"
+                                            disabled="@revokingSessionId.Equals(session.Id)">
+                                        Revoke
+                                    </button>
+                                }
+                                else
+                                {
+                                    <span class="badge bg-info">Current</span>
+                                }
+                            </td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+    }
+
+    @* Revoke Confirmation Dialog *@
+    @if (sessionToRevoke is not null)
+    {
+        <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
+            <div class="modal-dialog modal-dialog-centered">
+                <div class="modal-content">
+                    <div class="modal-header">
+                        <h5 class="modal-title">Revoke Session</h5>
+                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
+                    </div>
+                    <div class="modal-body">
+                        <p>Are you sure you want to revoke the session on <strong>@sessionToRevoke.Device</strong> in <strong>@sessionToRevoke.Location</strong>?</p>
+                    </div>
+                    <div class="modal-footer">
+                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
+                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@revoking">
+                            @if (revoking)
+                            {
+                                <span class="spinner-border spinner-border-sm me-1"></span>
+                            }
+                            Revoke
+                        </button>
+                    </div>
+                </div>
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
+    [Parameter, EditorRequired] public EventCallback<(string currentPassword, string newPassword)> OnPasswordChanged { get; set; }
+    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }
+
+    private bool passwordPanelOpen;
+    private string currentPassword = "";
+    private string newPassword = "";
+    private string confirmPassword = "";
+    private string? passwordError;
+    private bool passwordSuccess;
+    private bool changingPassword;
+
+    private ActiveSession? sessionToRevoke;
+    private bool revoking;
+    private string revokingSessionId = "";
+
+    private async Task ChangePasswordAsync()
+    {
+        passwordError = null;
+        passwordSuccess = false;
+
+        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
+        {
+            passwordError = "All password fields are required.";
+            return;
+        }
+
+        if (newPassword != confirmPassword)
+        {
+            passwordError = "New password and confirmation do not match.";
+            return;
+        }
+
+        if (newPassword.Length < 8)
+        {
+            passwordError = "New password must be at least 8 characters.";
+            return;
+        }
+
+        changingPassword = true;
+        try
+        {
+            await OnPasswordChanged.InvokeAsync((currentPassword, newPassword));
+            passwordSuccess = true;
+            currentPassword = "";
+            newPassword = "";
+            confirmPassword = "";
+        }
+        catch (Exception ex)
+        {
+            passwordError = ex.Message;
+        }
+        finally
+        {
+            changingPassword = false;
+        }
+    }
+
+    private void PromptRevoke(ActiveSession session)
+    {
+        sessionToRevoke = session;
+    }
+
+    private void CancelRevoke()
+    {
+        sessionToRevoke = null;
+    }
+
+    private async Task ConfirmRevokeAsync()
+    {
+        if (sessionToRevoke is null) return;
+
+        revoking = true;
+        revokingSessionId = sessionToRevoke.Id;
+        try
+        {
+            await OnSessionRevoked.InvokeAsync(sessionToRevoke.Id);
+            sessionToRevoke = null;
+        }
+        finally
+        {
+            revoking = false;
+            revokingSessionId = "";
+        }
+    }
+}
+

