@using sv_da423523ac9f486387eaf2c9987b0876.Services

<div class="settings-section">
    <h3 class="mb-4">Appearance Settings</h3>

    <div class="row">
        <div class="col-md-6">
            @* Theme *@
            <div class="mb-4">
                <label class="form-label fw-bold">Theme</label>
                <div>
                    @foreach (var option in themes)
                    {
                        <div class="form-check" @key="option">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="theme-@option" value="@option"
                                   checked="@(theme == option)"
                                   @onchange="() => theme = option" />
                            <label class="form-check-label" for="theme-@option">@option</label>
                        </div>
                    }
                </div>
            </div>

            @* Font Size *@
            <div class="mb-4">
                <label class="form-label fw-bold">Font Size</label>
                <div>
                    @foreach (var size in fontSizes)
                    {
                        <div class="form-check" @key="size">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="fs-@size" value="@size"
                                   checked="@(fontSize == size)"
                                   @onchange="() => fontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            @* Language *@
            <div class="mb-4">
                <label class="form-label fw-bold" for="languageSelect">Language</label>
                <select class="form-select" id="languageSelect" @bind="language">
                    @foreach (var lang in languages)
                    {
                        <option value="@lang.Key" @key="lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (showSuccess)
            {
                <div class="alert alert-success mt-3">✅ Appearance settings saved!</div>
            }
        </div>

        @* Live Preview *@
        <div class="col-md-6">
            <label class="form-label fw-bold">Live Preview</label>
            <div class="border rounded p-3 @PreviewThemeClass" style="@PreviewFontStyle min-height:200px;">
                <h5 style="@PreviewFontStyle">Preview Header</h5>
                <p style="@PreviewFontStyle" class="@(compactMode ? "mb-1" : "mb-3")">
                    This is how your content will look with the selected settings.
                </p>
                <p style="@PreviewFontStyle" class="@(compactMode ? "mb-1" : "mb-3")">
                    Theme: <strong>@theme</strong> ·
                    Font: <strong>@fontSize</strong> ·
                    Language: <strong>@languages.GetValueOrDefault(language, language)</strong>
                </p>
                <div class="d-flex gap-2 @(compactMode ? "mt-1" : "mt-3")">
                    <button class="btn btn-sm btn-primary" disabled>Sample Button</button>
                    <button class="btn btn-sm btn-outline-secondary" disabled>Cancel</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Appearance { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnAppearanceSaved { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool saving;
    private bool showSuccess;
    private CancellationTokenSource? toastCts;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> languages = new()
    {
        ["en"] = "English",
        ["es"] = "Spanish",
        ["fr"] = "French",
        ["de"] = "German",
        ["ja"] = "Japanese",
        ["zh"] = "Chinese"
    };

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "bg-dark text-light",
        "System" => "bg-secondary bg-opacity-10",
        _ => "bg-white text-dark"
    };

    private string PreviewFontStyle => fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.25rem;",
        _ => "font-size:1rem;"
    };

    protected override void OnParametersSet()
    {
        if (Appearance is not null && !saving)
        {
            theme = Appearance.Theme;
            fontSize = Appearance.FontSize;
            language = Appearance.Language;
            compactMode = Appearance.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        saving = true;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnAppearanceSaved.InvokeAsync(updated);
            showSuccess = true;
            StateHasChanged();
            await ShowToastAsync();
        }
        finally
        {
            saving = false;
        }
    }

    private async Task ShowToastAsync()
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        try
        {
            await Task.Delay(3000, toastCts.Token);
            showSuccess = false;
        }
        catch (TaskCanceledException) { }
    }
}

