using sv_da423523ac9f486387eaf2c9987b0876.Services;
using Microsoft.AspNetCore.Components;

namespace sv_da423523ac9f486387eaf2c9987b0876.Components.Pages.Settings;

public partial class Settings : IAsyncDisposable
{
    private string activeSection = "profile";
    private bool loading = true;
    private string? loadError;
    private CancellationTokenSource cts = new();

    private UserProfile? profile;
    private NotificationPrefs? notifications;
    private SecuritySettings? security;
    private AppearanceSettings? appearance;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            // Load all settings sections in parallel
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            profile = await profileTask;
            notifications = await notifTask;
            security = await securityTask;
            appearance = await appearanceTask;
        }
        catch (Exception ex)
        {
            loadError = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void ChangeSection(string section)
    {
        activeSection = section;
    }

    private async Task SaveProfileAsync(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notifications = updated;
    }

    private async Task HandlePasswordChangeAsync((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        // Reload security settings to get updated LastPasswordChange
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleSessionRevokeAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        // Reload to refresh session list
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        appearance = updated;
    }

    public ValueTask DisposeAsync()
    {
        cts.Cancel();
        cts.Dispose();
        return ValueTask.CompletedTask;
    }
}

