toolArgs.file_text:
.settings-dashboard {
    min-height: 500px;
}

.settings-nav {
    width: 220px;
    border-right: 1px solid var(--bs-border-color, #dee2e6);
    padding: 1rem 0;
}

::deep .settings-sidebar .nav-pills .nav-link {
    border-radius: 0;
    padding: 0.75rem 1.25rem;
    color: var(--bs-body-color, #212529);
    font-weight: 500;
}

::deep .settings-sidebar .nav-pills .nav-link:hover {
    background-color: var(--bs-tertiary-bg, #f8f9fa);
}

::deep .settings-sidebar .nav-pills .nav-link.active {
    background-color: var(--bs-primary, #0d6efd);
    color: #fff;
}

.settings-content {
    overflow-y: auto;
    max-height: 80vh;
}

